function active$VoucherFilter$(f) {f.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Reference':
      f.setItemControlBehavior('bp_ref', result[0].Value, true);
      break;
    case 'Checking':
      g._arrValue = []; g._arrSaved = []; g._rKey = '';
      g._$dept = f.getItemValue('bp_ref');
      break;
    default:
      break;
  }
}
function onchange$EmpsTimeInOut$Deparment(o) {o.parentForm.request('Reference', 'Reference', ['bo_phan']);}
